// Parity test: the TS port (`evalCheckIntent`) must match the on-chain
// reference (`SentryOracle.checkIntent` -> `PolicyLib.validate`) on every
// fixture generated by `contracts/test/PolicyEvalFixtures.t.sol`.
//
// If you change PolicyLib or SentryOracle semantics, re-run:
//   pnpm -F contracts test
// to regenerate the JSON, then update `sdk/src/policy-eval.ts` until this
// test passes again. That round-trip is the drift detector.

import { describe, it, expect } from "vitest";
import { readFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, resolve } from "node:path";
import type { Address, Hex } from "viem";
import { evalCheckIntent, evalPolicyFromInput } from "../src/policy-eval.js";
import type { EvalIntent } from "../src/policy-eval.js";
import type { PolicyInput, Tier } from "../src/types.js";

interface RawSelectorRule {
  selector: string;
  valueCapPerCall: string;
  tier: number;
  delaySeconds: number;
}
interface RawTargetRule {
  target: string;
  selectors: RawSelectorRule[];
}
interface RawPolicy {
  targets: RawTargetRule[];
  dailySpendWeiCap: string;
  maxSlippageBps: number;
  expiresAt: string;
  paused: boolean;
}
interface RawIntent {
  agentId: string;
  requestId: string;
  target: string;
  selector: string;
  data: string;
  value: string;
  promptHash: string;
  taskClass: number;
}
interface Fixture {
  name: string;
  policy: RawPolicy;
  intent: RawIntent;
  spentTodayWei: string;
  nowSec: string;
  expected: { ok: boolean; reason: string };
}

// Foundry's `vm.toString(bytes4)` left-pads to 32 bytes (0x + 64 hex chars).
// The Solidity `bytes4` selector is only the first 4 bytes (the rest is
// zero-padding from the bytes32 widen). Truncate to the canonical 0x + 8 hex
// form the TS evaluator + on-chain ABI expect.
function normalizeBytes4(hex: string): Hex {
  if (!hex.startsWith("0x")) throw new Error(`bad bytes4 ${hex}`);
  return (`0x${hex.slice(2, 10)}`).toLowerCase() as Hex;
}

function deserializePolicy(p: RawPolicy): PolicyInput {
  return {
    targets: p.targets.map((t) => ({
      target: t.target as Address,
      selectors: t.selectors.map((s) => ({
        selector: normalizeBytes4(s.selector),
        valueCapPerCall: BigInt(s.valueCapPerCall),
        tier: s.tier as Tier,
        delaySeconds: s.delaySeconds,
      })),
    })),
    dailySpendWeiCap: BigInt(p.dailySpendWeiCap),
    maxSlippageBps: p.maxSlippageBps,
    expiresAt: BigInt(p.expiresAt),
    paused: p.paused,
  };
}

function deserializeIntent(i: RawIntent): EvalIntent {
  return {
    agentId: BigInt(i.agentId),
    requestId: BigInt(i.requestId),
    target: i.target as Address,
    selector: normalizeBytes4(i.selector),
    data: i.data as Hex,
    value: BigInt(i.value),
    promptHash: i.promptHash as Hex,
    taskClass: i.taskClass,
  };
}

const here = dirname(fileURLToPath(import.meta.url));
const fixturePath = resolve(here, "./fixtures/policy-eval-fixtures.json");
const fixtures = JSON.parse(readFileSync(fixturePath, "utf8")) as Fixture[];

describe("PolicyLib parity — TS port vs Solidity reference", () => {
  it("loaded fixtures from forge output", () => {
    expect(fixtures.length).toBeGreaterThanOrEqual(30);
  });

  for (const fx of fixtures) {
    it(fx.name, () => {
      const policy = evalPolicyFromInput(deserializePolicy(fx.policy));
      const intent = deserializeIntent(fx.intent);
      const actual = evalCheckIntent(
        policy,
        intent,
        BigInt(fx.spentTodayWei),
        BigInt(fx.nowSec),
      );
      expect(actual.ok).toBe(fx.expected.ok);
      expect(actual.reason.toLowerCase()).toBe(fx.expected.reason.toLowerCase());
    });
  }
});
